import { useEffect, useState } from 'preact/hooks';
import { Workouts } from './tabs/Workouts';
import { Meditate } from './tabs/Meditate';
import { Checkin } from './tabs/Checkin';
import { Settings } from './tabs/Settings';

export type EntryTab = 'flux' | 'vibe' | 'balance';
export type TabKey = 'workouts' | 'meditate' | 'checkin' | 'settings';

const ENTRY_TO_TAB: Record<EntryTab, TabKey> = {
  flux: 'workouts',
  vibe: 'meditate',
  balance: 'checkin',
};

const VALID_ENTRIES: readonly EntryTab[] = ['flux', 'vibe', 'balance'];

const TABS: { key: TabKey; label: string }[] = [
  { key: 'workouts', label: 'Workouts' },
  { key: 'meditate', label: 'Meditate' },
  { key: 'checkin', label: 'Check-in' },
  { key: 'settings', label: 'Settings' },
];

export function App({ entry }: { entry: EntryTab }) {
  const [active, setActive] = useState<TabKey>(ENTRY_TO_TAB[entry]);

  // MainActivity.onNewIntent dispatches `app-entry-changed` when the user
  // re-launches a different alias while the app is already running.
  useEffect(() => {
    const onEntryChanged = (event: Event) => {
      const detail = (event as CustomEvent<unknown>).detail;
      if (typeof detail === 'string' && (VALID_ENTRIES as readonly string[]).includes(detail)) {
        setActive(ENTRY_TO_TAB[detail as EntryTab]);
      }
    };
    window.addEventListener('app-entry-changed', onEntryChanged);
    return () => window.removeEventListener('app-entry-changed', onEntryChanged);
  }, []);

  return (
    <div class="flex h-full flex-col bg-flux-bg text-flux-text-primary">
      <main
        class="flex-1 overflow-y-auto px-4 pb-28 pt-6 sm:px-6"
        data-active-tab={active}
      >
        {active === 'workouts' && <Workouts />}
        {active === 'meditate' && <Meditate />}
        {active === 'checkin' && <Checkin />}
        {active === 'settings' && <Settings />}
      </main>

      <nav
        class="pointer-events-none fixed inset-x-0 bottom-0 z-40 flex justify-center px-4 pb-4"
        role="tablist"
        aria-label="Primary"
      >
        <div class="pointer-events-auto grid w-full max-w-md grid-cols-4 gap-1 rounded-full bg-flux-card p-1.5 shadow-flux-nav">
          {TABS.map((t) => {
            const selected = active === t.key;
            return (
              <button
                key={t.key}
                type="button"
                role="tab"
                aria-selected={selected}
                data-tab={t.key}
                onClick={() => setActive(t.key)}
                class={
                  'rounded-full px-2 py-2.5 text-[10px] font-medium uppercase tracking-[0.18em] transition-all ' +
                  (selected
                    ? 'bg-flux-accent text-flux-card shadow-flux-soft'
                    : 'text-flux-text-tertiary hover:text-flux-text-secondary')
                }
              >
                {t.label}
              </button>
            );
          })}
        </div>
      </nav>
    </div>
  );
}

import { useEffect, useState } from 'preact/hooks';
import { useLLM } from '../llm';
import {
  applyImportFromFile,
  downloadExport,
  exportPayload,
  formatImportMessage,
} from './Workouts/logic/exportImport';
import { clearAll } from './Workouts/state';

const MODE_STORAGE_KEY = 'flux_mode';
type Mode = 'dark' | 'light';

function detectInitialMode(): Mode {
  if (typeof window === 'undefined') return 'dark';
  try {
    const stored = window.localStorage.getItem(MODE_STORAGE_KEY);
    if (stored === 'dark' || stored === 'light') return stored;
  } catch {
    // localStorage unavailable
  }
  return window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark';
}

function applyMode(mode: Mode): void {
  document.documentElement.setAttribute('data-mode', mode);
  try {
    window.localStorage.setItem(MODE_STORAGE_KEY, mode);
  } catch {
    // ignore
  }
}

export function Settings() {
  const { available } = useLLM();
  const [mode, setMode] = useState<Mode>(detectInitialMode);
  const [importMessage, setImportMessage] = useState<string | null>(null);

  useEffect(() => {
    applyMode(mode);
  }, [mode]);

  async function handleExport() {
    const payload = await exportPayload();
    downloadExport(payload);
  }

  async function handleImport(e: Event) {
    const input = e.target as HTMLInputElement;
    const file = input.files?.[0];
    input.value = '';
    if (!file) return;
    try {
      const result = await applyImportFromFile(file, { applyState: true });
      setImportMessage(formatImportMessage(result));
    } catch (err) {
      setImportMessage(
        'Import failed: ' + (err instanceof Error ? err.message : 'unknown error'),
      );
    }
  }

  async function handleReset() {
    if (!confirm('Reset all progress? This clears day count, exercise log, and loaded program.')) return;
    try {
      await clearAll();
      setImportMessage('Reset complete.');
    } catch (err) {
      setImportMessage(
        'Reset failed: ' + (err instanceof Error ? err.message : 'unknown error'),
      );
    }
  }

  return (
    <section class="mx-auto max-w-md space-y-5">
      <header class="flex flex-col items-center gap-1 pt-2 text-center">
        <h1 class="text-sm font-medium uppercase tracking-[0.28em] text-flux-text-primary">
          Settings
        </h1>
        <p class="text-[10px] uppercase tracking-[0.2em] text-flux-text-tertiary">
          Preferences & data
        </p>
      </header>

      <div class="rounded-[2rem] bg-flux-card p-6 shadow-flux-card">
        <h2 class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
          Appearance
        </h2>
        <div class="mt-4 inline-flex rounded-full bg-flux-soft p-1">
          {(['dark', 'light'] as const).map((m) => (
            <button
              key={m}
              type="button"
              class={
                'rounded-full px-4 py-1.5 text-[11px] font-medium uppercase tracking-[0.18em] transition-all ' +
                (mode === m
                  ? 'bg-flux-accent text-flux-card shadow-flux-soft'
                  : 'text-flux-text-secondary hover:text-flux-text-primary')
              }
              data-mode={m}
              onClick={() => setMode(m)}
            >
              {m}
            </button>
          ))}
        </div>
      </div>

      <div class="rounded-[2rem] bg-flux-card p-6 shadow-flux-card">
        <h2 class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
          LLM provider
        </h2>
        <p class="mt-3 text-sm text-flux-text-secondary">
          {available ? 'Configured' : 'Not configured'}
        </p>
      </div>

      <div class="rounded-[2rem] bg-flux-card p-6 shadow-flux-card">
        <h2 class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
          Data
        </h2>
        <div class="mt-4 flex flex-wrap items-center gap-2">
          <button
            type="button"
            class="rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-text-secondary transition-colors hover:text-flux-text-primary"
            onClick={handleExport}
            data-testid="export-btn"
          >
            Export
          </button>
          <label
            class="cursor-pointer rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-text-secondary transition-colors hover:text-flux-text-primary"
            data-testid="import-backup-label"
          >
            Import Backup
            <input
              type="file"
              accept="application/json,.json"
              class="hidden"
              onChange={handleImport}
              data-testid="import-input"
            />
          </label>
        </div>
        {importMessage && (
          <div
            class="mt-4 flex items-start justify-between gap-2 rounded-2xl bg-flux-soft px-4 py-3 text-xs text-flux-text-secondary"
            data-testid="backup-import-message"
          >
            <span class="flex-1">{importMessage}</span>
            <button
              type="button"
              onClick={() => setImportMessage(null)}
              class="shrink-0 text-flux-text-tertiary hover:text-flux-text-primary"
              aria-label="Dismiss"
              data-testid="backup-import-message-dismiss"
            >
              ×
            </button>
          </div>
        )}

        <div class="mt-5 border-t border-flux-border pt-4">
          <p class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-danger">
            Danger zone
          </p>
          <button
            type="button"
            class="mt-3 rounded-full bg-flux-soft px-4 py-2 text-[11px] font-medium uppercase tracking-[0.15em] text-flux-danger transition-opacity hover:opacity-80"
            onClick={handleReset}
            data-testid="reset-btn"
          >
            Reset all progress
          </button>
        </div>
      </div>
    </section>
  );
}

import type { LogEntry, ResolvedExercise } from '../types';
import { MAX_WEIGHT, MIN_WEIGHT, parseReps } from '../logic/progression';
import { parseSeconds } from '../logic/timer';
import { Timer } from './Timer';

interface Props {
  exercise: ResolvedExercise;
  index: number;
  globalDay: number;
  entry: LogEntry | undefined;
  suggestedWeight: number | null;
  lastWeight: number | null;
  onLog: (key: string, partial: Partial<LogEntry>, options?: { remove?: boolean }) => void;
  onPlayVideo: (videoId: string, start?: number) => void;
}

export function ExerciseCard({
  exercise,
  index,
  globalDay,
  entry,
  suggestedWeight,
  lastWeight,
  onLog,
  onPlayVideo,
}: Props) {
  const key = `${globalDay}_${index}`;
  const completed = entry?.completed ?? false;
  const difficulty = entry?.difficulty;
  const notes = entry?.notes ?? '';
  const weight = entry?.weight;
  const increment = exercise.weightIncrement ?? 5;
  const maxSets = exercise.sets;
  const maxReps = parseReps(exercise.reps);
  const failedSet = entry?.failedSet ?? 1;
  const failedRep = entry?.failedRep ?? 1;
  const repSeconds = parseSeconds(exercise.reps);
  const restSeconds = parseSeconds(exercise.rest);

  function setWeight(next: number | null) {
    if (next == null || Number.isNaN(next)) {
      onLog(key, { weight: undefined }, { remove: !difficulty && !notes });
      return;
    }
    const clamped = Math.max(MIN_WEIGHT, Math.min(MAX_WEIGHT, next));
    onLog(key, {
      exercise: exercise.name,
      weight: clamped,
      day: globalDay,
      timestamp: Date.now(),
    });
  }

  function handleWeightInput(e: Event) {
    const value = (e.target as HTMLInputElement).value;
    if (value === '') {
      setWeight(null);
      return;
    }
    const parsed = parseFloat(value);
    if (Number.isFinite(parsed)) setWeight(parsed);
  }

  function setDifficulty(d: LogEntry['difficulty']) {
    onLog(key, {
      exercise: exercise.name,
      difficulty: d,
      day: globalDay,
      timestamp: Date.now(),
      ...(d !== 'failed' ? { failedSet: undefined, failedRep: undefined } : {}),
    });
  }

  function setNotes(value: string) {
    const trimmed = value.trim();
    onLog(
      key,
      {
        exercise: exercise.name,
        notes: trimmed || undefined,
        day: globalDay,
        timestamp: Date.now(),
      },
      { remove: !trimmed && !weight && !difficulty && !completed },
    );
  }

  function toggleDone() {
    if (completed) {
      onLog(
        key,
        { completed: undefined },
        { remove: !weight && !difficulty && !notes },
      );
    } else {
      onLog(key, {
        exercise: exercise.name,
        completed: true,
        day: globalDay,
        timestamp: Date.now(),
      });
    }
  }

  const placeholder = suggestedWeight != null ? String(suggestedWeight) : lastWeight != null ? String(lastWeight) : '—';

  return (
    <article
      class={
        'rounded-[2rem] p-6 transition-all ' +
        (completed
          ? 'bg-flux-accent/15 shadow-flux-card'
          : 'bg-flux-card shadow-flux-card')
      }
      data-exercise-index={index}
      data-completed={completed ? 'true' : 'false'}
    >
      <header class="flex items-start justify-between gap-3">
        <div class="flex-1">
          <h3 class="text-lg font-medium leading-tight text-flux-text-primary">
            {exercise.name}
          </h3>
          {exercise.unmapped && (
            <span
              class="mt-1 inline-block rounded-full bg-flux-soft px-2.5 py-0.5 text-[10px] uppercase tracking-[0.15em] text-flux-text-tertiary"
